mapper.select:
SELECT
FROM dish d LEFT JOIN category c ON d.category_id = c.id LEFT JOIN user u ON d.owner_user_id = u.id WHERE d.status = 1 AND d.is_featured = 1 AND d.visibility = 'public'
AND d.category_id = #{categoryId}
ORDER BY d.updated_at DESC, d.created_at DESC LIMIT #{limit}

SELECT
FROM dish d LEFT JOIN category c ON d.category_id = c.id LEFT JOIN user u ON d.owner_user_id = u.id LEFT JOIN dish_visibility_circle dvc ON dvc.dish_id = d.id AND dvc.circle_id = #{circleId} WHERE d.status = 1 AND d.owner_user_id = #{ownerUserId}
AND (d.visibility = 'public' OR dvc.circle_id IS NOT NULL) ORDER BY d.updated_at DESC, d.created_at DESC

SELECT
FROM dish d LEFT JOIN category c ON d.category_id = c.id LEFT JOIN user u ON d.owner_user_id = u.id WHERE d.id IN
#{id}
